  'type' => 'function',
  'function' => 
  array (
    'name' => 'db_schema_explorer',
    'description' => 'Introspect a database (MySQL, PostgreSQL, or SQLite) and return its full schema: all tables, columns with types/nullable/defaults, primary keys, indexes, foreign keys, and row counts. Uses PHP\'s PDO to connect and queries INFORMATION_SCHEMA / pg_catalog / sqlite_master depending on database type. First cross-database introspection tool in the ecosystem — no tool discovers and describes database schemas. Never throws — all errors returned as structured data.',
    'parameters' => 
