if (! function_exists('db_schema_explorer')) {
    function db_schema_explorer($type, $database, $host = null, $port = null, $user = null, $password = null, $exclude_tables = null, $timeout = null, $include_row_counts = null)
    {
        $db_type = $type ?? '';
        $host = $host ?? '127.0.0.1';
        $port = $port ?? 0;
        $database = $database ?? '';
        $user = $user ?? '';
        $password = $password ?? '';
        $exclude_tables = $exclude_tables ?? '';
        $timeout = $timeout ?? 10;
        $timeout = max(5, min(30, $timeout));
        $include_row_counts = $include_row_counts ?? true;

        $db_type = strtolower(trim($db_type));
        if (!in_array($db_type, ['mysql', 'pgsql', 'sqlite'], true)) {
            return ['error' => 'Database type must be "mysql", "pgsql", or "sqlite". Got: ' . $db_type];
        }

        if (empty($database)) {
            return ['error' => 'Database name/path is required.'];
        }

        // Set defaults per type
        if ($db_type === 'mysql') {
            if (empty($user)) $user = 'root';
            if ($port === 0) $port = 3306;
        } elseif ($db_type === 'pgsql') {
            if (empty($user)) $user = 'postgres';
            if ($port === 0) $port = 5432;
        }

        $start = microtime(true);

        try {
            if ($db_type === 'sqlite') {
                $dbPath = $database;
                // Check workspace if relative
                if (!file_exists($dbPath) && strpos($dbPath, DIRECTORY_SEPARATOR) === false) {
                    $workspace = getcwd() . DIRECTORY_SEPARATOR . 'storage' . DIRECTORY_SEPARATOR . 'agent' . DIRECTORY_SEPARATOR . 'workspace';
                    $candidate = $workspace . DIRECTORY_SEPARATOR . $dbPath;
                    if (file_exists($candidate)) {
                        $dbPath = $candidate;
                    }
                }
                $dsn = "sqlite:{$dbPath}";
                $pdo = new PDO($dsn, null, null, [
                    PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
                    PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
                ]);
            } elseif ($db_type === 'mysql') {
                $dsn = "mysql:host={$host};port={$port};dbname={$database};charset=utf8mb4";
                $pdo = new PDO($dsn, $user, $password, [
                    PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
                    PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
                    PDO::ATTR_TIMEOUT => $timeout,
                ]);
            } else {
                $dsn = "pgsql:host={$host};port={$port};dbname={$database}";
                $pdo = new PDO($dsn, $user, $password, [
                    PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
                    PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
                ]);
            }
        } catch (\Throwable $e) {
            return ['error' => 'Connection failed: ' . $e->getMessage(), 'type' => $db_type, 'database' => $database];
        }

        $exclude_patterns = [];
        if (!empty($exclude_tables)) {
            foreach (explode(',', $exclude_tables) as $pat) {
                $pat = trim($pat);
                if ($pat !== '') {
                    $exclude_patterns[] = $pat;
                }
            }
        }

        $should_exclude = function($tableName) use ($exclude_patterns) {
            foreach ($exclude_patterns as $pat) {
                if (fnmatch($pat, $tableName)) return true;
            }
            return false;
        };

        $schema = [
            'type' => $db_type,
            'database' => $database,
            'server_info' => '',
            'tables' => [],
            'total_tables' => 0,
            'sampled_tables' => 0,
        ];

        // Get server info
        try {
            if ($db_type === 'sqlite') {
                $schema['server_info'] = 'SQLite ' . $pdo->getAttribute(PDO::ATTR_SERVER_VERSION);
            } elseif ($db_type === 'mysql') {
                $schema['server_info'] = $pdo->getAttribute(PDO::ATTR_SERVER_VERSION);
            } else {
                $schema['server_info'] = $pdo->getAttribute(PDO::ATTR_SERVER_VERSION);
            }
        } catch (\Throwable $e) {
            $schema['server_info'] = 'unknown';
        }

        // Get table list
        try {
            if ($db_type === 'mysql') {
                $tables = $pdo->query("SELECT TABLE_NAME, TABLE_TYPE, TABLE_ROWS, ENGINE, TABLE_COLLATION, CREATE_TIME, TABLE_COMMENT 
                    FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_SCHEMA = " . $pdo->quote($database) . "
                    ORDER BY TABLE_NAME")->fetchAll();
            } elseif ($db_type === 'pgsql') {
                $tables = $pdo->query("SELECT tablename AS TABLE_NAME, 'BASE TABLE' AS TABLE_TYPE 
                    FROM pg_catalog.pg_tables WHERE schemaname = 'public' 
                    UNION ALL 
                    SELECT viewname AS TABLE_NAME, 'VIEW' AS TABLE_TYPE 
                    FROM pg_catalog.pg_views WHERE schemaname = 'public'
                    ORDER BY TABLE_NAME")->fetchAll();
            } else {
                $tables = $pdo->query("SELECT name AS TABLE_NAME, type AS TABLE_TYPE 
                    FROM sqlite_master WHERE type IN ('table','view') AND name NOT LIKE 'sqlite_%'
                    ORDER BY name")->fetchAll();
            }
        } catch (\Throwable $e) {
            return ['error' => 'Failed to list tables: ' . $e->getMessage()];
        }

        $table_count = 0;
        foreach ($tables as $tbl) {
            $tbl_name = $tbl['TABLE_NAME'];
            $tbl_type = $tbl['TABLE_TYPE'] ?? 'BASE TABLE';
            
            if ($should_exclude($tbl_name)) continue;
            $table_count++;
            
            $table_info = [
                'name' => $tbl_name,
                'type' => ($tbl_type === 'VIEW' || $tbl_type === 'view') ? 'VIEW' : 'TABLE',
                'columns' => [],
                'indexes' => [],
                'primary_key' => null,
                'foreign_keys' => [],
                'row_count' => null,
            ];
            
            // Row count
            if ($include_row_counts) {
                try {
                    if ($db_type === 'mysql') {
                        $table_info['row_count'] = (int)($tbl['TABLE_ROWS'] ?? 0);
                    } elseif ($db_type === 'pgsql') {
                        $cnt = $pdo->query("SELECT reltuples::bigint AS cnt FROM pg_class WHERE relname = " . $pdo->quote($tbl_name))->fetch();
                        $table_info['row_count'] = (int)($cnt['cnt'] ?? 0);
                    } else {
                        $cnt = $pdo->query("SELECT COUNT(*) AS cnt FROM \"{$tbl_name}\"")->fetch();
                        $table_info['row_count'] = (int)($cnt['cnt'] ?? 0);
                    }
                } catch (\Throwable $e) {
                    $table_info['row_count'] = -1;
                }
            }
            
            // MySQL extra info
            if ($db_type === 'mysql') {
                if (isset($tbl['ENGINE'])) $table_info['engine'] = $tbl['ENGINE'];
                if (isset($tbl['TABLE_COLLATION'])) $table_info['collation'] = $tbl['TABLE_COLLATION'];
                $table_info['comment'] = $tbl['TABLE_COMMENT'] ?? '';
            }
            
            // Get columns
            try {
                if ($db_type === 'mysql') {
                    $cols = $pdo->query("SELECT COLUMN_NAME, DATA_TYPE, IS_NULLABLE, COLUMN_DEFAULT, 
                        CHARACTER_MAXIMUM_LENGTH, NUMERIC_PRECISION, NUMERIC_SCALE, COLUMN_TYPE, EXTRA, COLUMN_KEY, COLUMN_COMMENT
                        FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA = " . $pdo->quote($database) . " 
                        AND TABLE_NAME = " . $pdo->quote($tbl_name) . " ORDER BY ORDINAL_POSITION")->fetchAll();
                } elseif ($db_type === 'pgsql') {
                    $cols = $pdo->query("SELECT 
                        a.attname AS COLUMN_NAME,
                        pg_catalog.format_type(a.atttypid, a.atttypmod) AS DATA_TYPE,
                        CASE WHEN a.attnotnull THEN 'NO' ELSE 'YES' END AS IS_NULLABLE,
                        pg_catalog.pg_get_expr(ad.adbin, ad.adrelid) AS COLUMN_DEFAULT,
                        CASE WHEN a.attnum > 0 THEN a.attnum ELSE NULL END AS ORDINAL_POSITION
                        FROM pg_catalog.pg_attribute a
                        LEFT JOIN pg_catalog.pg_attrdef ad ON a.attrelid = ad.adrelid AND a.attnum = ad.adnum
                        WHERE a.attrelid = (SELECT oid FROM pg_catalog.pg_class WHERE relname = " . $pdo->quote($tbl_name) . " AND relnamespace = (SELECT oid FROM pg_catalog.pg_namespace WHERE nspname = 'public'))
                        AND a.attnum > 0 AND NOT a.attisdropped
                        ORDER BY a.attnum")->fetchAll();
                } else {
                    $cols = $pdo->query("PRAGMA table_info(\"{$tbl_name}\")")->fetchAll();
                }
            } catch (\Throwable $e) {
                $table_info['columns_error'] = $e->getMessage();
                $cols = [];
            }
            
            foreach ($cols as $col) {
                if ($db_type === 'sqlite') {
                    $col_name = $col['name'];
                    $col_type = $col['type'];
                    $nullable = $col['notnull'] ? 'NO' : 'YES';
                    $default = $col['dflt_value'];
                    $is_pk = $col['pk'] ? true : false;
                    
                    $table_info['columns'][] = [
                        'name' => $col_name,
                        'type' => $col_type,
                        'nullable' => $nullable === 'YES',
                        'default' => $default,
                        'primary_key' => $is_pk,
                        'auto_increment' => false,
                    ];
                    
                    if ($is_pk) {
                        $table_info['primary_key'] = $col_name;
                    }
                } else {
                    $col_name = $col['COLUMN_NAME'];
                    $col_type = $db_type === 'mysql' ? $col['COLUMN_TYPE'] : $col['DATA_TYPE'];
                    $nullable = $col['IS_NULLABLE'] ?? 'YES';
                    $default = $col['COLUMN_DEFAULT'] ?? null;
                    $extra = $col['EXTRA'] ?? '';
                    $is_pk = ($col['COLUMN_KEY'] ?? '') === 'PRI';
                    
                    $column_entry = [
                        'name' => $col_name,
                        'type' => $col_type,
                        'nullable' => $nullable === 'YES',
                        'default' => $default,
                        'primary_key' => $is_pk,
                        'auto_increment' => strpos($extra, 'auto_increment') !== false,
                    ];
                    
                    if ($db_type === 'mysql' && !empty($col['CHARACTER_MAXIMUM_LENGTH'])) {
                        $column_entry['max_length'] = (int)$col['CHARACTER_MAXIMUM_LENGTH'];
                    }
                    if ($db_type === 'mysql' && !empty($col['COLUMN_COMMENT'])) {
                        $column_entry['comment'] = $col['COLUMN_COMMENT'];
                    }
                    
                    $table_info['columns'][] = $column_entry;
                    
                    if ($is_pk) {
                        $table_info['primary_key'] = $col_name;
                    }
                }
            }
            
            // Get indexes (MySQL/SQLite)
            try {
                if ($db_type === 'mysql') {
                    $idxs = $pdo->query("SHOW INDEX FROM `{$tbl_name}`")->fetchAll();
                    $idx_map = [];
                    foreach ($idxs as $idx) {
                        $name = $idx['Key_name'];
                        if (!isset($idx_map[$name])) {
                            $idx_map[$name] = [
                                'name' => $name,
                                'unique' => !$idx['Non_unique'],
                                'type' => $idx['Index_type'],
                                'columns' => [],
                            ];
                        }
                        $idx_map[$name]['columns'][] = $idx['Column_name'];
                    }
                    $table_info['indexes'] = array_values($idx_map);
                } elseif ($db_type === 'sqlite') {
                    $idxs = $pdo->query("PRAGMA index_list(\"{$tbl_name}\")")->fetchAll();
                    foreach ($idxs as $idx) {
                        $name = $idx['name'];
                        $detail = $pdo->query("PRAGMA index_info(\"{$name}\")")->fetchAll();
                        $cols = [];
                        foreach ($detail as $d) {
                            $cols[] = $d['name'];
                        }
                        $table_info['indexes'][] = [
                            'name' => $name,
                            'unique' => (bool)$idx['unique'],
                            'columns' => $cols,
                        ];
                    }
                }
            } catch (\Throwable $e) {
                // Non-critical
            }
            
            // Get foreign keys (MySQL/SQLite)
            try {
                if ($db_type === 'mysql') {
                    $fks = $pdo->query("SELECT COLUMN_NAME, REFERENCED_TABLE_NAME, REFERENCED_COLUMN_NAME
                        FROM INFORMATION_SCHEMA.KEY_COLUMN_USAGE 
                        WHERE TABLE_SCHEMA = " . $pdo->quote($database) . " 
                        AND TABLE_NAME = " . $pdo->quote($tbl_name) . "
                        AND REFERENCED_TABLE_NAME IS NOT NULL")->fetchAll();
                    foreach ($fks as $fk) {
                        $table_info['foreign_keys'][] = [
                            'column' => $fk['COLUMN_NAME'],
                            'references_table' => $fk['REFERENCED_TABLE_NAME'],
                            'references_column' => $fk['REFERENCED_COLUMN_NAME'],
                        ];
                    }
                } elseif ($db_type === 'sqlite') {
                    $fks = $pdo->query("PRAGMA foreign_key_list(\"{$tbl_name}\")")->fetchAll();
                    foreach ($fks as $fk) {
                        $table_info['foreign_keys'][] = [
                            'column' => $fk['from'],
                            'references_table' => $fk['table'],
                            'references_column' => $fk['to'],
                        ];
                    }
                }
            } catch (\Throwable $e) {
                // Non-critical
            }
            
            $schema['tables'][] = $table_info;
        }

        $schema['total_tables'] = count($schema['tables']);
        $schema['elapsed_seconds'] = round(microtime(true) - $start, 4);

        return $schema;
    }
}
